class ControlFlow{static debounce(fn,delay=300,immediate=!1){let timeout;return function(...args){const callNow=immediate&&!timeout;clearTimeout(timeout),timeout=setTimeout((()=>{timeout=null,immediate||fn.apply(this,args)}),delay),callNow&&fn.apply(this,args)}}static throttle(fn,limit=300){let inThrottle=!1;return function(...args){inThrottle||(fn.apply(this,args),inThrottle=!0,setTimeout((()=>inThrottle=!1),limit))}}static rafThrottle(fn){let ticking=!1;return function(...args){ticking||(requestAnimationFrame((()=>{fn.apply(this,args),ticking=!1})),ticking=!0)}}static idle(fn,timeout=1e3){return"requestIdleCallback"in window?requestIdleCallback(fn,{timeout:timeout}):setTimeout(fn,timeout)}static batch(processFn,delay=1e3){let queue=[];return setInterval((()=>{queue.length&&(processFn(queue),queue=[])}),delay),function(item){queue.push(item)}}static lock(fn){let isRunning=!1;return async function(...args){if(!isRunning){isRunning=!0;try{return await fn.apply(this,args)}finally{isRunning=!1}}}}static abortableFetch(){let controller;return async function(url,options={}){controller&&controller.abort(),controller=new AbortController;try{const res=await fetch(url,{...options,signal:controller.signal});return await res.json()}catch(err){if("AbortError"!==err.name)throw err}}}static rateLimit(fn,limit=5,interval=1e3){let tokens=limit;return setInterval((()=>{tokens=limit}),interval),function(...args){if(tokens>0)return tokens--,fn.apply(this,args)}}}export{ControlFlow};